******************************************************************  FMCRO - Expand Macros**  Checks the current line.  If it is not a macro, an error is*  returned.  If it is a macro, the macro is expanded and the*  resulting source is sent through passes 1 and 2.**  INPUTS:*	LINE - source line******************************************************************FMCRO	START	LONGA OFF	LONGI OFF	DEBUG FMCRO	JSR	SIMAC	initialize for a macro find	BCC	MC3	JSR	SFMAC	find the macro definition	BCS	MC1	ERROR #13,R	unidentified operation	BRL	MC2MC1	JSR	SEMAC	expand the macroMC2	JSR	STMAC	terminal processingMC3	RTS	END******************************************************************  SDMSP - Define Macro Symbolic Parameter******************************************************************SDMSP	START	USING COMMON	LONGA OFF	LONGI OFF	DEBUG SDMSP	CLC	JSR	SDSPC	LDA	ERR	BNE	RTS	PHY	JSR	SINSP	PLYRTS	RTS	END******************************************************************  SEMAC - Expand a Macro**  INPUTS:*	MTP - pointer to the macro model line*	MIN - macro library number*	LINE - macro call line**  OUTPUTS:*	MCNT - number of macros expanded******************************************************************SEMAC	START	USING MACDAT	USING COMMON	USING OPCODE	LONGA OFF	LONGI OFF	DEBUG SEMAC;;  Initialization.;	LDX	PASS	if PASS = 1 then update number of	CPX	#1	 expansions	BNE	IN1	INC4	MCNTIN1	LONG	I,M	increment and save SYSCNT	INC4	HSCNT	HSCNT = max(HSCNT+1, SYSCNT)	ADD4	SFIRST,#DISPVAL,R0	LDY	#2	LDA	HSCNT+2	CMP	[R0],Y	BNE	IN1A	LDA	HSCNT	CMP	[R0]IN1A	BGE	IN1B	LDA	[R0],Y	STA	HSCNT+2	LDA	[R0]	STA	HSCNTIN1B	LDA	[R0]	STA	LSCNT	LDA	HSCNT	STA	[R0]	LDA	[R0],Y	STA	LSCNT+2	LDA	HSCNT+2	STA	[R0],Y	SHORT I,M	JSR	SMSTK	save recursive variables	LDY	LISTLEN	DEYIN2	LDA	LISTTOP,Y	STA	(R0),Y	DBPL	Y,IN2	LM	ACTR,#$FF	init the ACTR counter	LDX	#$FF	save the source lineIN3	INX	LDA	LINE,X	STA	WORK2,X	CMP	#RETURN	BNE	IN3	LONG	I,M	MOVE4 MTP,AP	get the macro def line	MOVE4 MACEND,SRCEND	SHORT I,M	LM	SOURCE,#1	JSR	SRLIN;;  Evaluate the macro.;	LDX	#L:LINE-1	find out how many bytes must be swappedCT1	LDA	LINE,X	 by SWTCH	CMP	WORK2,X	BNE	CT2	DEX	BNE	CT1CT2	STX	SWITCHLEN	JSR	SMLAB	evaluate the label field	JSR	SMOPN	evaluate the operand field	LDA	ERR	BNE	EV4	JSR	SERAS	erase unused parms	JSR	SWTCH	list the macro call	JSR	SMLST	LDA	ERR	BNE	EV4	JSR	SWTCHEV1	JSR	SINTP	get the next line	LDA	AP+2	branch if at the end of the file	CMP	SRCEND+2	BNE	EV1A	LDA	AP+1	CMP	SRCEND+1	BNE	EV1A	LDA	AP	CMP	SRCENDEV1A	BGE	EV5	JSR	FORML	form it	LDA	OP	quit if MEND or MEXIT	CMP	#IMEND	BEQ	EV4	CMP	#IMEXIT	BEQ	EV4	LDA	PASS	send line to proper pass	CMP	#1	BNE	EV2	JSR	FPAS1	BRA	EV3EV2	JSR	FPAS2EV3	JSR	SUPST	update STR	BRA	EV1	next lineEV4	RTSEV5	ERROR #18	No MEND	END******************************************************************  SERAS - Erase Undefined Sym Parms******************************************************************SERAS	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG SERAS	JSR	SMTR0	set search limits	LDA	FLAB	branch if no label was declared	BEQ	ES1	JSR	SINMT	skip label so it won't be erasedES1	LONG	M	check for done	LDA	R0	ORA	R2	SHORT M	BEQ	ES4	LDY	#DISPSPCT	check sym parm	LDA	[R0],Y	CMP	#1	BNE	ES3	LDY	#DISPVAL	LONG	M	LDA	[R0],Y	INY	INY	ORA	[R0],Y	SHORT M	BNE	ES3	LONG	M	erase it by making it invisible to	LDA	[R0]	 the search routine	STA	R4	LDY	#2	LDA	[R0],Y	STA	R6	SHORT M	LDA	#' '	LDY	#1	STA	[R4],YES3	JSR	SINMT	next parm	BRA	ES1ES4	RTS	END******************************************************************  SFMAC - Find the Macro Definition**  INPUTS:*	MOP - op code characters*	MOPLEN - length of MOP (always odd)*	MIN - macro library in memory*	MLIB - active library flags*	MHDISP - macro hash table displacement**  OUTPUTS:*	C - set if macro definition found, else clear*	MTP - pointer to the macro definition line in the*		loaded macro library*	MIN - macro library containing the macro******************************************************************SFMAC	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG SFMAC;;  Get a macro library to search.;	LM	TN,#4	init the library search counter	LM	TMIN,MIN	save the current library number	BPL	CK1	skip the first load if a library is!			 in memoryGL1	LDA	MTNL	quit now if macro is nested	BNE	GL2	DEC	TN	TN = next library number to check	BMI	GL2	LDX	TN	skip check if its the one we started	CPX	TMIN	 with	BEQ	GL1	LDA	MLIB,X	skip check if there is no library by	BEQ	GL1	 this number	JSR	LoadMacros	load the library	BRL	CK1GL2	CLC		error return	RTS;;  Scan the current library for the macro.;CK1	LONG	I,M	ADD4	MHASH,MHDISP,R4	init search point	LDA	[R4]	STA	R0	LDY	#2	LDA	[R4],Y	STA	R2CK2	LDA	R0	if at end of list then go check the next	ORA	R2	 library	BNE	CK2A	SHORT I,M	BRA	GL1	LONGA ON	LONGI ONCK2A	LDA	MOPLEN	check this macro for a match	LDY	#8	CMP	[R0],Y	BNE	CK4	AND	#$FF	LSR	A	BEQ	CK3A	TAX	LDY	#10CK3	LDA	MOPLEN-8,Y	CMP	[R0],Y	BNE	CK4	INY	INY	DBNE	X,CK3CK3A	LDA	[R0]	match found -> record the position	STA	MTP	LDY	#2	LDA	[R0],Y	STA	MTP+2	MOVE4 MACEND,SRCEND	SHORT I,M	SEC	RTS	LONGA ON	LONGI ONCK4	LDY	#4	next macro	LDA	[R0],Y	TAX	INY	INY	LDA	[R0],Y	STA	R2	STX	R0	BRL	CK2	LONGA OFF	LONGI OFFTMIN	DS	1	MIN at start of searchTN	DS	1	current table number	END******************************************************************  SIMAC - Macro Processor Initialization**  INPUTS:*	LINE - source line*	MTNL - macro next level**  OUTPUTS:*	MOP - macro op code*	MOPLEN - length of MOP (always odd)*	C - set if initialization was successful******************************************************************SIMAC	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG SIMAC	LDA	ENDF	if not in segment then	BEQ	IN0	ERROR #16,R	  misplaced statement	CLC	RTSIN0	INC	MTNL	bump the recursion level	LDX	MTNL	if its too high, return with error	CPX	#4	BNE	IN1	DEC	MTNL	ERROR #9,R	nest level exceeded	CLC	RTSIN1	JSR	SFNOP	read the macro op code	LDX	#0IN2	LDA	LINE,Y	JSR	SHIFT	CMP	#' '	BEQ	IN3	CMP	#RETURN	BEQ	IN3	STA	MOP,X	STA	LNAME+1,X	INY	INX	BNE	IN2IN3	TXA		get hash table displacement	LSR	A	BCS	IN3A	INX	LDA	#' '	STA	MOP-1,X	STA	LNAME,XIN3A	STX	LNAME	STX	MOPLEN	JSR	SHASH	LONG	I,M	MOVE4 R0,MHDISP	MOVE4 AP,STP	save the source file pointer	MOVE4 SRCEND,MSEND	SHORT I,M	JSR	SMSTK	save the recursive variables (for the	LONG	I,M	MOVE	LISTTOP,{R0},LISTLEN	 case of an error return)	JSR	SETSP	set symbol table pointers	STZ	CFIRST	STZ	CFIRST+2	JSR	SAVSP	SHORT I,M	SEC	RTS	END******************************************************************  SMLAB - Evaluate Macro Label******************************************************************SMLAB	START	USING COMMON	USING MACDAT	DEBUG SMLAB	STZ	FLAB	indicate no label declared	LDA	LINE	quit if there is no sym parm in the	CMP	#' '	 macro definition line	JEQ	RTS	CMP	#'&'	BNE	ERR4	LDY	#0	JSR	SDMSP	define the parameter	INC	FLAB	indicate that a label was declared	JSR	SWTCH	get the label	LDY	#0	JSR	SLABL	LDY	LNAME	STY	PFIX	BEQ	ML0AML0	LDA	LNAME,Y	STA	PFIX,Y	DBNE	Y,ML0ML0A	JSR	SMTR0	LDY	PFIX	set the sym parm	STY	WORK	STY	STLEN	BEQ	ML1AML1	LDA	PFIX,Y	STA	WORK,Y	DBNE	Y,ML1ML1A	LDX	WORK	if the label ends with space, remove it	LDA	WORK,X	CMP	#' '	BNE	ML2	DEC	WORKML2	LM	SPCT,#1	JSR	SSTSP	JSR	SWTCHRTS	RTSERR4	ERROR #4	Label Syntax	END******************************************************************  SMLST - Gets Macro Definition Listed******************************************************************	LONGA OFF	LONGI OFFSMLST	START	USING COMMON	LONGA OFF	LONGI OFF	DEBUG SMLST	LDA	PASS	br if PASS 2	CMP	#2	BNE	RTS	LDA	MTNL	br if MTNL>0	BNE	ML1	DEC	MTNL	list line	LM	OPF,#$D	JSR	SLIST	INC	MTNLRTS	RTSML1	LDA	GENER	list line if GENER=.TRUE.	BEQ	RTS	BRL	SLIST	END******************************************************************  SMOPN - Macro Operand Evaluation**  INPUTS:*	LINE - model source line*	WORK2 - call source line******************************************************************SMOPN	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG SMOPN;;  Check for macro operand.;	STZ	NSP	NSP=# of sym parms	JSR	SOPRF	br if no operands	BCS	CK0	RTSCK0	STY	TY	LDX	#0	check for & SYSOPRCK1	LDA	LINE,Y	JSR	SHIFT	CMP	SYS,X	BNE	EN1	INY	INX	CPX	#L:SYS	BNE	CK1	LDA	LINE,Y	CMP	#RETURN	BEQ	ES0	CMP	#' '	BNE	EN1;;  & sysopr operand;ES0	LDY	TY	define & SYSOPR	JSR	SDMSP	LDA	ERR	BNE	RTS3	JSR	SWTCH	switch to source line	JSR	SOPRF	JCC	SWTCH	LDX	#0	move charactersES1	LDA	LINE,Y	CMP	#RETURN	BEQ	ES2	STA	WORK+1,X	INX	INY	BRA	ES1ES2	STX	WORK	STX	STLEN	JSR	SWTCH	LDY	TY	INY	JSR	SSPFN	MOVE4 R4,R0	LM	SPCT,#1	JSR	SSTSPRTS3	RTS;;  Evaluate normal macro operand.;EN1	LDY	TY	reset YEN2	LDA	LINE,Y	insure &	CMP	#'&'	BEQ	EN3EN2A	ERROR #30	MACRO Operand Syntax ErrorEN3	JSR	SDMSP	define sym parm	LDA	ERR	JNE	SWTCH	INC	NSP	# = # + 1	LDA	LINE,Y	quit if space	CMP	#' '	BEQ	EN5	CMP	#RETURN	BEQ	EN5	CMP	#','	error if not comma	BNE	EN2A	INY	BNE	EN2	do continuationsEN5	JSR	SWTCH	switch to source line	JSR	SOPRF	JCC	SWTCHEN6	STZ	FSP	set position countEN7	LDA	LINE,Y	quit if space	CMP	#' '	JEQ	SWTCH	CMP	#RETURN	JEQ	SWTCH	CMP	#','	loop if comma	JEQ	EN16	CMP	#'('	  or '()'	BNE	EN8	LDA	LINE+1,Y	CMP	#')'	BNE	EN8	INY	BRL	EN16EN8	STY	TY	scan for = outside quotesEN9	LDA	LINE,Y	CMP	#' '	BEQ	EN11	CMP	#RETURN	BEQ	EN11	JSR	SQUOT	BCS	EN10	CMP	#','	BEQ	EN11	CMP	#'='	BEQ	EN13	INY	BNE	EN9EN10	INY		scan to next quote	CMP	LINE,Y	BNE	EN10	INY	BNE	EN9EN11	JSR	SMTR0	set R0 to the FSPth sym parm	LONG	M	... quit now if there are none	LDA	R0	ORA	R2	SHORT M	JEQ	EN18	LDA	NSP	... error if there aren't that many	CMP	FSP	JLE	EN2A	CLC		... set # parms to skip over	LDA	FLAB	ADC	FSP	BEQ	EN12A	STA	R13	... loop to proper oneEN12	JSR	SINMT	DBNE	R13,EN12EN12A	LDY	TY	BRA	EN15EN13	STY	R13	set R0 to the sym parm named	LDY	TY	JSR	SSPFN	LDX	ERR	BNE	RTS	MOVE4 R4,R0	CPY	R13	BEQ	EN14EN13A	BRL	EN2AEN14	INY	LDA	LINE,Y	if form is parm=() then	CMP	#'('	BNE	EN15	LDA	LINE+1,Y	CMP	#')'	BEQ	EN13A	  syntax errorEN15	JSR	STEVL	evaluate string	STY	TY	set sym parm	JSR	SSTSP	LDY	TYEN16	LDA	LINE,Y	check syntax	CMP	#' '	BEQ	RTS	CMP	#RETURN	BEQ	RTS	CMP	#','	BNE	EN13A	INY	INC	FSP	inc position cnt	BRL	EN7	LDA	LINE,Y	if not blank then too many sym parms	CMP	#' '	BEQ	RTS	CMP	#RETURN	BEQ	RTSEN18	ERROR #26,R	Too Many Positional ParametersRTS	BRL	SWTCHNSP	DS	1	# of sym parms definedFSP	DS	1	# of sym parm being expandedSYS	DC	C'&',C'SYSOPR'	END******************************************************************  SMSTK - Compute Recursion Stack Address**  Finds the address in the macro recursion stack area where*  the variables for this level are saved.**  INPUTS:*	LISTLEN - length of recursive variables*	MTNL - recursion level**  OUTPUTS:*	R0 - address of variable save are******************************************************************SMSTK	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG SMSTK	LA	R0,MSTK	LDX	MTNL	BEQ	MS3MS1	ADD2	R0,LISTLEN	DBNE	X,MS1MS3	RTS	END******************************************************************  SMTR0 - Set R0 to point to the head of the sym parm chain******************************************************************SMTR0	START	USING MACDAT	USING COMMON	DEBUG SMTR0	LONG	I,M	LDA	MTNL	INC	A	AND	#$FF	ASL	A	ASL	A	TAX	LDA	SFIRST,X	STA	R0	LDA	SFIRST+2,X	STA	R2	SHORT I,M	RTS	END******************************************************************  SSTSP - Set Symbolic Parameter**  Inputs:*	R0 - points to sym parm to set******************************************************************SSTSP	START	USING COMMON	USING MACDAT	LONGI OFF	DEBUG SSTSP	LM	SMTNL,MTNL	set string check MTNL	LONG	M	skip duplicate check if no parms	LDA	R0	ORA	R2	SHORT M	BEQ	SP1	LDY	#DISPSPCT	flag error if the sym parm has already	LDA	[R0],Y	 been set	CMP	#1	BNE	ERR27	LDY	#DISPSPL	LDA	[R0],Y	BNE	ERR27	STA	SPL	get sym parm length	LDY	#DISPSPCT	set the count	LDA	SPCT	STA	[R0],Y	LDY	#DISPSPL	set the length to non-zero	STA	[R0],Y	 (L of char sym parm not directly used)	CMP	#1	branch if subscripted	BNE	SP1	ADD4	R0,#DISPVAL,R4	insert the sym parm value	BRL	STRNGERR27	ERROR #27	Duplicate Ref in MACRO Opnd;;  Handle a subscripted symbolic parameter;SP1	LDY	#DISPVAL	move the parm to a local bufferSP2	LDA	[R0],Y	STA	WORK2,Y	DBPL	Y,SP2	LONG	I,M	JSR	SETSP	set sym parm table vectors	MOVE4 R8,SAVE	save some ZP space	MOVE4 R12,SAVE+4	MOVE4 R0,R8	save the pointer	LDA	SPCT	find a spot for the parm	AND	#$FF	ASL	A	ASL	A	ADC	#DISPVAL	LDX	#3	JSR	SROOM	JSR	SAVSP	save the sym parm pointers	LDA	CFIRST	if this is the first parm in the list	CMP	R8	 then	BNE	SP3	LDA	CFIRST+2	CMP	R10	BNE	SP3	INC	FLAB	  fake a label entry	LDY	#2	  give it a dummy name	LDA	#DUMMY	STA	[R8]	LDA	#^DUMMY	STA	[R8],Y	INY		  point the dummy label to the new	INY		   parameter	LDA	R0	STA	[R8],Y	INY	INY	LDA	R2	STA	[R8],Y	BRA	SP7SP3	MOVE4 CFIRST,R12	else find the parent of this parmSP4	LDY	#4	  quit if this parm points to the	LDA	[R12],Y	   one being subscripted	TAX	INY	INY	LDA	[R12],Y	CPX	R8	BNE	SP5	CMP	R10	BEQ	SP6SP5	STX	R12	  next parm	STA	R14	BRA	SP4SP6	LDY	#4	  point the parent to the new entry	LDA	R0	STA	[R12],Y	INY	INY	LDA	R2	STA	[R12],YSP7	ANOP		endif	MOVE4 R0,R8	save pointer to new symbol	LDA	#WORK2+DISPVAL	R4 = address of pointer to string	STA	R4	LDA	#^WORK2+DISPVAL	STA	R6	MOVE	WORK,WORD,#256	save subscripted string	SHORT I,M	STZ	R15	R15 = disp into WORD	LM	R14,SPCT	for R14 = SPCT downto 1 doSP8	LDX	R15	  move a string to WORK	LDY	#0SP9	LDA	WORD,X	INX	STA	WORK,Y	CPY	WORK	BEQ	SP10	INY	BNE	SP9SP10	STX	R15	JSR	STRNG	  save the string and set its pointer	ADD4	R4,#4	  update string handle	DBNE	R14,SP8	next R14	LONG	I,M	move the sym parm into its buffer	LDA	SPCT	AND	#$FF	ASL	A	ASL	A	ADC	#DISPVAL	DEC	A	TAY	SHORT MSP11	LDA	WORK2,Y	STA	[R8],Y	DBPL	Y,SP11	MOVE4 SAVE,R8	restore ZP	MOVE4 SAVE+4,R12	SHORT I	RTSSAVE	DS	8DUMMY	DW	' '	END******************************************************************  STEVL - Evaluates Strings in Macro Model Statements**  INPUTS:*	Y - disp of start of string in line**  OUTPUTS:*	WORK - resultant string*	STLEN - length of string*	Y - points to 1st char past string******************************************************************STEVL	START	USING COMMON	LONGA OFF	LONGI OFF	DEBUG STEVL;;  Initialization.;	STZ	STLEN	LENGTH=0	STZ	SPCT	SPCT=0	STZ	STFLG	STFLG=.FALSE.	LDA	LINE,Y	br if not (	CMP	#'('	BNE	STEV;;  Subscripted string.;	INC	STFLG	STFLG=.TRUE.SV1	INY		next char	LDA	LINE,Y	error if )	CMP	#')'	BEQ	SV2	JSR	STEV	evaluate string	INC	STLEN	set for next parm	LDA	LINE,Y	loop if ,	CMP	#','	BEQ	SV1	CMP	#')'	error if not )	BEQ	SV3SV2	ERROR #7	operand syntax errSV3	INY	DEC	STLEN	RTS;..............................................................;;					       ;;  STEV - Evaluate non-subscripted string.		       ;;					       ;;..............................................................;;STEV	JSR	SWORD2	string -> WORD	LDA	STFLG	remove end ) if STFLG = .TRUE.	BEQ	ST0	LDX	WORD	LDA	WORD,X	CMP	#')'	BNE	ST0	DEC	WORD	DEYST0	STY	TY	init loop variables	LDX	STLEN	LDY	#$FFST1	INY		move string	LDA	WORD,Y	STA	WORK,X	INX	CPY	WORD	BNE	ST1	DEX		restore variables	STX	STLEN	LDY	TY	INC	SPCT	SPCT = SPCT+1	RTSSTFLG	DS	1	subscript flag	END******************************************************************  STMAC - Terminate Macro Processing**  INPUTS:*	MTNL - macro next level**  NOTES:*	1)  All variables restored to pre-macro state.*	2)  Returns to caller of FPAS1 of FPAS2.******************************************************************STMAC	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG STMAC	JSR	SETSP	LONG	I,M	MOVE4 SPHAND,R0	delete extents to symbol table	JSR	SDELT	MOVE4 R0,SPHAND	restore table parameters	LDY	#2	LDA	[R0]	STA	CSTART	LDA	[R0],Y	STA	CSTART+2	ADD4	CSTART,#4,CSP	ADD4	CSTART,#ASIZE,CEND	SHORT I,M	JSR	SAVSP	LM	LMIN,MIN	save MIN	JSR	SMSTK	reset stack variables	PHY	LONG	M,I	MOVE	{R0},LISTTOP,LISTLEN	ADD4	SFIRST,#DISPVAL,R0	reset SYSCNT	LDA	LSCNT	STA	[R0]	LDY	#2	LDA	LSCNT+2	STA	[R0],Y	SHORT M,I	PLY	LDA	MTNL	if this was not a recursive call,	BNE	TM2	 reset SOURCE	STA	SOURCE	 (SOURCE = 0)TM2	PHY		reload the call line	MOVE4 STP,AP	MOVE4 MSEND,SRCEND	PLY	JSR	SRLIN	DEC	MTNL	reset the recursion level	STZ	LENGTH	fake the length	STZ	LENGTH+1	STZ	LENGTH+2	STZ	LENGTH+3	STZ	LLNAME	RTSLMIN	DS	1	local MIN	END******************************************************************  SWTCH - Switch the Call and Model Lines**  INPUTS:*	LINE, WORK2 - lines to switch******************************************************************SWTCH	START	USING COMMON	USING MACDAT	LONGA OFF	LONGI OFF	DEBUG SWTCH	LONG	I,M	LDA	SWITCHLEN	TAX	LSR	A	BCS	LB1	SHORT M	LDA	LINE,X	LDY	WORK2,X	STA	WORK2,X	TYA	STA	LINE,X	LONG	M	DEX	BMI	LB3LB1	DEXLB2	LDA	LINE,X	LDY	WORK2,X	STA	WORK2,X	TYA	STA	LINE,X	DEX	DEX	BPL	LB2LB3	SHORT I,M	RTS	END